// TOPIC_CHANNELS 파싱: 채널별 아이템 생성
// 형식: 채널이름/채널ID+채널이름/채널ID+...
const raw = ($env.TOPIC_CHANNELS || '').trim();
if (!raw) {
  return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];
}

const items = [];
const invalid = [];

for (const chunk of raw.split('+')) {
  const part = (chunk || '').trim();
  if (!part) continue;

  const slashIdx = part.indexOf('/');
  if (slashIdx < 0) {
    invalid.push(`${part}(구분자 '/' 없음)`);
    continue;
  }

  const channelName = part.slice(0, slashIdx).trim();
  const channelId = part.slice(slashIdx + 1).trim();

  if (!channelName || !channelId) {
    invalid.push(`${part}(채널명/채널ID 비어 있음)`);
    continue;
  }

  items.push({ json: { channelId, channelName } });
}

console.log(`[WF-09] parsed channels: valid=${items.length}, invalid=${invalid.length}`);
if (invalid.length) {
  console.log(`[WF-09] invalid TOPIC_CHANNELS entries: ${invalid.join(', ')}`);
}

if (!items.length) {
  return [{ json: { skip: true, reason: '유효한 채널 없음' } }];
}

return items;

// 채널별 active notebook 상태 확인 + 빈 notebook에만 최신 recent video 1개 선택
const channelId = ($json.channelId || '').trim();
const channelName = ($json.channelName || '').trim();

if (!channelId) {
  return { json: { skip: true, channelId, channelName, reason: 'channelId 없음' } };
}

let notebookState;
try {
  notebookState = await this.helpers.httpRequest({
    method: 'POST',
    url: `${$env.NOTEBOOKLM_SERVICE_URL}/notebook-state`,
    headers: {
      'Content-Type': 'application/json',
      'X-Internal-Secret': $env.GATEWAY_INTERNAL_SECRET,
    },
    body: { channel_id: channelId },
    json: true,
    timeout: 30000,
  });
} catch (e) {
  const msg = e && e.message ? e.message : String(e);
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `notebook-state 조회 실패(${msg.slice(0, 200)})`,
      sourceResolver: '',
      resolverAttempts: 0,
      resolverErrors: [msg.slice(0, 300)],
    },
  };
}

if (!notebookState || notebookState.status !== 'success' || !notebookState.notebook_url) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `active notebook 없음(${(notebookState && notebookState.error) || 'unknown'})`,
      sourceResolver: '',
      resolverAttempts: 0,
      resolverErrors: [String((notebookState && notebookState.error) || 'unknown')],
    },
  };
}

const notebookUrl = (notebookState.notebook_url || '').trim();
const activeSourceCount = Number.isFinite(Number(notebookState.active_source_count)) ? Number(notebookState.active_source_count) : 0;
const activeReportCount = Number.isFinite(Number(notebookState.active_report_count)) ? Number(notebookState.active_report_count) : 0;
const hasSources = Boolean(notebookState.has_sources);
const hasReports = Boolean(notebookState.has_reports);
const lookbackRaw = ($env.WF09_LOOKBACK_HOURS || '').trim();
const parsedLookback = Number.parseFloat(lookbackRaw);
const lookbackHours = Number.isFinite(parsedLookback) && parsedLookback > 0 ? parsedLookback : 24;
const CUTOFF_MS = Date.now() - lookbackHours * 60 * 60 * 1000;
const CUTOFF_ISO = new Date(CUTOFF_MS).toISOString();

if (hasSources) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode: 'skip-existing-sources',
      reason: `active notebook already has sources(${activeSourceCount})`,
      lookbackHours,
      cutoffIso: CUTOFF_ISO,
      selectedStrategy: 'skip-existing-sources',
      sourceResolver: '',
      resolverAttempts: 0,
      resolverErrors: [],
    },
  };
}

const seedMode = 'initial-empty-notebook';
let resolved;
try {
  resolved = await this.helpers.httpRequest({
    method: 'POST',
    url: `${$env.NOTEBOOKLM_SERVICE_URL}/resolve-latest-video`,
    headers: {
      'Content-Type': 'application/json',
      'X-Internal-Secret': $env.GATEWAY_INTERNAL_SECRET,
    },
    body: {
      channel_id: channelId,
      channel_name: channelName,
      lookback_hours: lookbackHours,
      exclude_shorts: true,
    },
    json: true,
    timeout: 150000,
  });
} catch (e) {
  const msg = e && e.message ? e.message : String(e);
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: 'source-resolver-failed',
      resolverAttempts: 0,
      resolverErrors: [msg.slice(0, 300)],
      sourceResolver: '',
      lookbackHours,
      cutoffIso: CUTOFF_ISO,
    },
  };
}

const resolverErrors = Array.isArray(resolved?.errors) ? resolved.errors : [];
const resolverAttempts = Number.isFinite(Number(resolved?.attempts)) ? Number(resolved.attempts) : 0;
const sourceResolver = (resolved?.resolver || '').trim();

if (!resolved || resolved.status !== 'success') {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: 'source-resolver-failed',
      resolverAttempts,
      resolverErrors: resolverErrors.length ? resolverErrors : [String(resolved?.error || 'unknown')],
      sourceResolver,
      lookbackHours,
      cutoffIso: CUTOFF_ISO,
    },
  };
}

if (!resolved.found || !resolved.video_url) {
  const lastError = resolverErrors.length ? resolverErrors[resolverErrors.length - 1] : '';
  const resolverFailed = resolverErrors.some((err) => /^(rss|yt_dlp):/i.test(String(err)) && !String(err).includes('no-recent-video-within-lookback'));
  const reason = resolverFailed ? 'source-resolver-failed' : 'no-recent-video-within-lookback';
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason,
      resolverAttempts,
      resolverErrors,
      sourceResolver,
      lookbackHours,
      cutoffIso: CUTOFF_ISO,
      selectedStrategy: reason,
      error: lastError || String(resolved.error || ''),
    },
  };
}

return {
  json: {
    videoUrl: resolved.video_url,
    title: resolved.title || '',
    publishedAt: resolved.published_at || '',
    channelId,
    channelName,
    notebookUrl,
    activeSourceCount,
    hasSources,
    activeReportCount,
    hasReports,
    seedMode,
    cutoffIso: CUTOFF_ISO,
    lookbackHours,
    sourceResolver,
    resolverAttempts,
    resolverErrors,
    selectedStrategy: sourceResolver ? `latest-recent-via-${sourceResolver}` : 'latest-recent-resolved',
    forceAutoReport: false,
  },
};

// 결과 로깅 + auto-report 트리거(소스 추가 성공 + 복구 경로)
const result = $input.item.json || {};
const source = $('RSS 조회 + 새 영상 필터링').item.json || result;

const callAutoReport = async (reasonLabel, payload) => {
  if (!payload.channel_id) {
    result.auto_report_status = 'skipped';
    result.auto_report_reason = 'missing-channel-id';
    return;
  }

  try {
    const parsed = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://messenger-gateway:8080/internal/auto-report',
      headers: {
        'Content-Type': 'application/json',
        'X-Internal-Secret': $env.GATEWAY_INTERNAL_SECRET,
      },
      body: payload,
      json: true,
      timeout: 30000,
    });

    result.auto_report_status = parsed.status || 'triggered';
    result.auto_report_reason = parsed.reason || reasonLabel;
    result.auto_report_job_id = parsed.job_id || '';
    result.auto_report_notebook_url = parsed.notebook_url || source.notebookUrl || '';
    result.auto_report_attempts_today = parsed.attempts_today;
    result.auto_report_limit = parsed.max_attempts_per_day;
    const shortId = (result.auto_report_job_id || '').slice(0, 8);
    console.log(`[WF-09] auto-report ${result.auto_report_status} channel=${payload.channel_id} reason=${result.auto_report_reason || reasonLabel} job=${shortId || '(none)'}`);
  } catch (e) {
    const msg = e && e.message ? e.message : String(e);
    result.auto_report_status = 'failed';
    result.auto_report_reason = reasonLabel;
    result.auto_report_error = msg.slice(0, 300);
    console.error(`[WF-09] auto-report trigger error channel=${payload.channel_id}: ${result.auto_report_error}`);
  }
};

// 복구 경로: 소스는 있는데 보고서가 없는 active notebook
if (result.skip === true) {
  const hasSources = Boolean(source.hasSources);
  const hasReports = Boolean(source.hasReports);
  if (hasSources && !hasReports) {
    await callAutoReport('recovery-no-report', {
      channel_id: source.channelId || '',
      channel_name: source.channelName || '',
      source_url: source.videoUrl || '',
      source_title: source.title || '',
    });
  } else {
    result.auto_report_status = 'skipped';
    result.auto_report_reason = source.reason || 'skip';
  }
  return { json: result };
}

if (result.duplicate) {
  const hasReports = Boolean(source.hasReports);
  if (!hasReports) {
    await callAutoReport('duplicate-no-report', {
      channel_id: source.channelId || '',
      channel_name: source.channelName || '',
      source_url: source.videoUrl || '',
      source_title: source.title || '',
    });
  } else {
    result.auto_report_status = 'skipped';
    result.auto_report_reason = 'duplicate-source';
  }
  return { json: result };
}

if (result.added) {
  console.log(`[WF-09] source added channel=${source.channelId || '(unknown)'} notebook=${source.notebookUrl || '(unknown)'} sourceCountBefore=${source.activeSourceCount ?? '(unknown)'} strategy=${source.selectedStrategy || '(unknown)'} cleaned=${result.cleaned_up}`);
  await callAutoReport('source-added', {
    channel_id: source.channelId || '',
    channel_name: source.channelName || '',
    source_url: source.videoUrl || '',
    source_title: source.title || '',
  });
  return { json: result };
}

if (result.error) {
  console.error(`[WF-09] source add failed channel=${source.channelId || '(unknown)'} strategy=${source.selectedStrategy || '(unknown)'}: ${result.error}`);
}

result.auto_report_status = result.auto_report_status || 'skipped';
result.auto_report_reason = result.auto_report_reason || 'no-action';
return { json: result };
